import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Profile {
  username: string;
  followers: number;
  engagementRate: number;
}

interface GrowthTrend {
  day: string;
  followers: number;
}

interface WidgetData {
  profile: Profile;
  growthTrend: GrowthTrend[];
}

export default function Widget() {
  const { profile, growthTrend } = response.data as WidgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#000000' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF' }}>
              {profile.username}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Followers: {profile.followers.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Engagement Rate: {profile.engagementRate.toFixed(1)}%
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: growthTrend.map(item => item.followers),
                color: response.meta.primaryColor,
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[{ data: growthTrend.map(item => item.day), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
